 201→	s, err := LoadEntireSettings()
 202→	if err != nil || !s.Enabled {
 203→		return false, "", ""
 204→	}
 205→
 206→	// Check any agent hooks installed (not just Claude Code — works with Gemini too)
 207→	installedAgents := GetAgentsWithHooksInstalled()
 208→	if len(installedAgents) == 0 {
 209→		return false, "", ""
 210→	}
 211→
 212→	// Check git hooks installed
 213→	if !strategy.IsGitHookInstalled() {
 214→		return false, "", ""
 215→	}
