 217→	// Check .entire directory exists
 218→	if !checkEntireDirExists() {
 219→		return false, "", ""
 220→	}
 221→
 222→	// Determine agent description from first installed agent
 223→	desc := string(installedAgents[0]) // fallback to agent name
 224→	if ag, err := agent.Get(installedAgents[0]); err == nil {
 225→		desc = string(ag.Type())
 226→	}
