 242→// runEnableWithStrategy enables Entire with a specified strategy (non-interactive).
 243→// The selectedStrategy can be either a display name (manual-commit, auto-commit)
 244→// or an internal name (manual-commit, auto-commit).
 245→// agents must be provided by the caller (via detectOrSelectAgent).
 246→func runEnableWithStrategy(w io.Writer, agents []agent.Agent, selectedStrategy string, localDev, useLocalSettings, useProjectSettings, forceHooks, skipPushSessions, telemetry bool) error {
 247→	// Map the strategy to internal name if it's a display name
 248→	internalStrategy := selectedStrategy
 249→	if mapped, ok := strategyDisplayToInternal[selectedStrategy]; ok {
 250→		internalStrategy = mapped
 251→	}
 252→
 253→	// Validate the strategy exists
 254→	strat, err := strategy.Get(internalStrategy)
 255→	if err != nil {
 256→		return fmt.Errorf("unknown strategy: %s (use manual-commit or auto-commit)", selectedStrategy)
 257→	}
 258→
 259→	// Setup agent hooks for all selected agents
 260→	for _, ag := range agents {
 261→		if _, err := setupAgentHooks(ag, localDev, forceHooks); err != nil {
 262→			return fmt.Errorf("failed to setup %s hooks: %w", ag.Type(), err)
 263→		}
 264→	}
 265→
 266→	// Setup .entire directory
 267→	if _, err := setupEntireDirectory(); err != nil {
 268→		return fmt.Errorf("failed to setup .entire directory: %w", err)
 269→	}
 270→
 271→	// Load existing settings to preserve other options (like strategy_options.push)
 272→	settings, err := LoadEntireSettings()
 273→	if err != nil {
 274→		// If we can't load, start with defaults
 275→		settings = &EntireSettings{}
 276→	}
 277→	// Update the specific fields
 278→	settings.Strategy = internalStrategy
 279→	settings.LocalDev = localDev
 280→	settings.Enabled = true
 281→
 282→	// Set push_sessions option if --skip-push-sessions flag was provided
 283→	if skipPushSessions {
 284→		if settings.StrategyOptions == nil {
 285→			settings.StrategyOptions = make(map[string]interface{})
 286→		}
 287→		settings.StrategyOptions["push_sessions"] = false
 288→	}
 289→
 290→	// Handle telemetry for non-interactive mode
 291→	// Note: if telemetry is nil (not configured), it defaults to disabled
 292→	if !telemetry || os.Getenv("ENTIRE_TELEMETRY_OPTOUT") != "" {
 293→		f := false
 294→		settings.Telemetry = &f
 295→	}
 296→
 297→	// Determine which settings file to write to
 298→	entireDirAbs, err := paths.AbsPath(paths.EntireDir)
 299→	if err != nil {
 300→		entireDirAbs = paths.EntireDir // Fallback to relative
 301→	}
 302→	shouldUseLocal, showNotification := determineSettingsTarget(entireDirAbs, useLocalSettings, useProjectSettings)
 303→
 304→	if showNotification {
 305→		fmt.Fprintln(w, "Info: Project settings exist. Saving to settings.local.json instead.")
 306→		fmt.Fprintln(w, "  Use --project to update the project settings file.")
 307→	}
 308→
 309→	configDisplay := configDisplayProject
 310→	if shouldUseLocal {
 311→		if err := SaveEntireSettingsLocal(settings); err != nil {
 312→			return fmt.Errorf("failed to save local settings: %w", err)
 313→		}
 314→		configDisplay = configDisplayLocal
 315→	} else {
 316→		if err := SaveEntireSettings(settings); err != nil {
 317→			return fmt.Errorf("failed to save settings: %w", err)
 318→		}
 319→	}
 320→
 321→	// Install git hooks AFTER saving settings (InstallGitHook reads local_dev from settings)
 322→	if _, err := strategy.InstallGitHook(true); err != nil {
 323→		return fmt.Errorf("failed to install git hooks: %w", err)
 324→	}
 325→	strategy.CheckAndWarnHookManagers(w)
 326→	fmt.Fprintln(w, "✓ Hooks installed")
 327→	fmt.Fprintf(w, "✓ Project configured (%s)\n", configDisplay)
 328→
 329→	// Let the strategy handle its own setup requirements
 330→	if err := strat.EnsureSetup(); err != nil {
 331→		return fmt.Errorf("failed to setup strategy: %w", err)
 332→	}
 333→
 334→	fmt.Fprintln(w, "\nReady.")
 335→
 336→	return nil
 337→}
