 515→// detectOrSelectAgent tries to auto-detect agents, or prompts the user to select.
 516→// Returns the detected/selected agents and any error.
 517→// When exactly one agent is detected, it is used automatically.
 518→// When multiple agents are detected, the user is prompted to confirm.
 519→// If no agent is detected and no TTY is available, falls back to the default agent.
 520→//
 521→// selectFn overrides the interactive prompt for testing. When nil, the real form is used.
 522→// It receives available agent names and returns the selected names.
 523→func detectOrSelectAgent(w io.Writer, selectFn func(available []string) ([]string, error)) ([]agent.Agent, error) {
 524→	// Try auto-detection first
 525→	detected := agent.DetectAll()
 526→
 527→	switch {
 528→	case len(detected) == 1:
 529→		// Single agent detected — use it directly
 530→		fmt.Fprintf(w, "Detected agent: %s\n\n", detected[0].Type())
 531→		return detected, nil
 532→
 533→	case len(detected) > 1:
 534→		// Multiple agents detected — prompt the user to confirm which to enable
 535→		agentTypes := make([]string, 0, len(detected))
 536→		for _, ag := range detected {
 537→			agentTypes = append(agentTypes, string(ag.Type()))
 538→		}
 539→		fmt.Fprintf(w, "Detected multiple agents: %s\n", strings.Join(agentTypes, ", "))
 540→		fmt.Fprintln(w)
 541→		// Fall through to the interactive multi-select below
 542→	}
 543→
 544→	// No agent detected (or multiple detected) — check if we can prompt interactively
 545→	if !canPromptInteractively() {
 546→		if len(detected) > 0 {
 547→			// Multiple agents detected but no TTY — use all of them
 548→			return detected, nil
 549→		}
 550→		// No TTY available (e.g., running in CI or tests) - fall back to default agent
 551→		defaultAgent := agent.Default()
 552→		if defaultAgent == nil {
 553→			return nil, errors.New("no default agent available")
 554→		}
 555→		fmt.Fprintf(w, "Agent: %s (use --agent to change)\n\n", defaultAgent.Type())
 556→		return []agent.Agent{defaultAgent}, nil
 557→	}
 558→
 559→	if len(detected) == 0 {
 560→		// Show message only when nothing was detected
 561→		fmt.Fprintln(w, "No agent configuration detected (e.g., .claude or .gemini directory).")
 562→		fmt.Fprintln(w, "This is normal - some agents don't require a config directory.")
 563→		fmt.Fprintln(w)
 564→	}
 565→
 566→	// Build a set of detected agent names for pre-selection
 567→	detectedSet := make(map[agent.AgentName]struct{}, len(detected))
 568→	for _, ag := range detected {
 569→		detectedSet[ag.Name()] = struct{}{}
 570→	}
 571→
 572→	// Build options from registered agents
 573→	agentNames := agent.List()
 574→	options := make([]huh.Option[string], 0, len(agentNames))
 575→	for _, name := range agentNames {
 576→		ag, err := agent.Get(name)
 577→		if err != nil {
 578→			continue
 579→		}
 580→		// Only show agents that support hooks
 581→		if _, ok := ag.(agent.HookSupport); !ok {
 582→			continue
 583→		}
 584→		label := string(ag.Type())
 585→		if name == agent.DefaultAgentName {
 586→			label += " (default)"
 587→		}
 588→		opt := huh.NewOption(label, string(name))
 589→		if _, isDetected := detectedSet[name]; isDetected {
 590→			opt = opt.Selected(true)
 591→		}
 592→		options = append(options, opt)
 593→	}
 594→
 595→	if len(options) == 0 {
 596→		return nil, errors.New("no agents with hook support available")
 597→	}
 598→
 599→	// Collect available agent names for the selector
 600→	availableNames := make([]string, 0, len(options))
 601→	for _, opt := range options {
 602→		availableNames = append(availableNames, opt.Value)
 603→	}
 604→
 605→	var selectedAgentNames []string
 606→	if selectFn != nil {
 607→		var err error
 608→		selectedAgentNames, err = selectFn(availableNames)
 609→		if err != nil {
 610→			return nil, err
 611→		}
 612→	} else {
 613→		form := NewAccessibleForm(
 614→			huh.NewGroup(
 615→				huh.NewMultiSelect[string]().
 616→					Title("Which agents are you using?").
 617→					Description("Use space to select, enter to confirm.").
 618→					Options(options...).
 619→					Value(&selectedAgentNames),
 620→			),
 621→		)
 622→		if err := form.Run(); err != nil {
 623→			return nil, fmt.Errorf("agent selection cancelled: %w", err)
 624→		}
 625→	}
 626→
 627→	if len(selectedAgentNames) == 0 {
 628→		return nil, errors.New("no agents selected")
 629→	}
 630→
 631→	selectedAgents := make([]agent.Agent, 0, len(selectedAgentNames))
 632→	for _, name := range selectedAgentNames {
 633→		selectedAgent, err := agent.Get(agent.AgentName(name))
 634→		if err != nil {
 635→			return nil, fmt.Errorf("failed to get selected agent %s: %w", name, err)
 636→		}
 637→		selectedAgents = append(selectedAgents, selectedAgent)
 638→	}
 639→
 640→	agentTypes := make([]string, 0, len(selectedAgents))
 641→	for _, ag := range selectedAgents {
 642→		agentTypes = append(agentTypes, string(ag.Type()))
 643→	}
 644→	fmt.Fprintf(w, "\nSelected agents: %s\n\n", strings.Join(agentTypes, ", "))
 645→	return selectedAgents, nil
 646→}
