 648→// canPromptInteractively checks if we can show interactive prompts.
 649→// Returns false when running in CI, tests, or other non-interactive environments.
 650→func canPromptInteractively() bool {
 651→	// Check for test environment
 652→	if os.Getenv("ENTIRE_TEST_TTY") != "" {
 653→		return os.Getenv("ENTIRE_TEST_TTY") == "1"
 654→	}
 655→
 656→	// Check if /dev/tty is available
 657→	tty, err := os.OpenFile("/dev/tty", os.O_RDWR, 0)
 658→	if err != nil {
 659→		return false
 660→	}
 661→	_ = tty.Close()
 662→	return true
 663→}
