 691→// setupAgentHooksNonInteractive sets up hooks for a specific agent non-interactively.
 692→// If strategyName is provided, it sets the strategy; otherwise uses default.
 693→func setupAgentHooksNonInteractive(w io.Writer, ag agent.Agent, strategyName string, localDev, forceHooks, skipPushSessions, telemetry bool) error {
 694→	agentName := ag.Name()
 695→	// Check if agent supports hooks
 696→	hookAgent, ok := ag.(agent.HookSupport)
 697→	if !ok {
 698→		return fmt.Errorf("agent %s does not support hooks", agentName)
 699→	}
 700→
 701→	fmt.Fprintf(w, "Agent: %s\n\n", ag.Type())
 702→
 703→	// Install agent hooks (agent hooks don't depend on settings)
 704→	installedHooks, err := hookAgent.InstallHooks(localDev, forceHooks)
 705→	if err != nil {
 706→		return fmt.Errorf("failed to install hooks for %s: %w", agentName, err)
 707→	}
 708→
 709→	// Setup .entire directory
 710→	if _, err := setupEntireDirectory(); err != nil {
 711→		return fmt.Errorf("failed to setup .entire directory: %w", err)
 712→	}
 713→
 714→	// Load existing settings to preserve other options (like strategy_options.push)
 715→	settings, err := LoadEntireSettings()
 716→	if err != nil {
 717→		// If we can't load, start with defaults
 718→		settings = &EntireSettings{Strategy: strategy.DefaultStrategyName}
 719→	}
 720→	settings.Enabled = true
 721→	if localDev {
 722→		settings.LocalDev = localDev
 723→	}
 724→
 725→	// Set push_sessions option if --skip-push-sessions flag was provided
 726→	if skipPushSessions {
 727→		if settings.StrategyOptions == nil {
 728→			settings.StrategyOptions = make(map[string]interface{})
 729→		}
 730→		settings.StrategyOptions["push_sessions"] = false
 731→	}
 732→
 733→	// Set strategy if provided
 734→	if strategyName != "" {
 735→		// Map display name to internal name if needed
 736→		internalStrategy := strategyName
 737→		if mapped, ok := strategyDisplayToInternal[strategyName]; ok {
 738→			internalStrategy = mapped
 739→		}
 740→		// Validate the strategy exists
 741→		if _, err := strategy.Get(internalStrategy); err != nil {
 742→			return fmt.Errorf("unknown strategy: %s (use manual-commit or auto-commit)", strategyName)
 743→		}
 744→		settings.Strategy = internalStrategy
 745→	}
 746→
 747→	// Handle telemetry for non-interactive mode
 748→	// Note: if telemetry is nil (not configured), it defaults to disabled
 749→	if !telemetry || os.Getenv("ENTIRE_TELEMETRY_OPTOUT") != "" {
 750→		f := false
 751→		settings.Telemetry = &f
 752→	}
 753→
 754→	if err := SaveEntireSettings(settings); err != nil {
 755→		return fmt.Errorf("failed to save settings: %w", err)
 756→	}
 757→
 758→	// Install git hooks AFTER saving settings (InstallGitHook reads local_dev from settings)
 759→	if _, err := strategy.InstallGitHook(true); err != nil {
 760→		return fmt.Errorf("failed to install git hooks: %w", err)
 761→	}
 762→	strategy.CheckAndWarnHookManagers(w)
 763→
 764→	if installedHooks == 0 {
 765→		msg := fmt.Sprintf("Hooks for %s already installed", ag.Description())
 766→		if agentName == agent.AgentNameGemini {
 767→			msg += " (Preview)"
 768→		}
 769→		fmt.Fprintf(w, "%s\n", msg)
 770→	} else {
 771→		msg := fmt.Sprintf("Installed %d hooks for %s", installedHooks, ag.Description())
 772→		if agentName == agent.AgentNameGemini {
 773→			msg += " (Preview)"
 774→		}
 775→		fmt.Fprintf(w, "%s\n", msg)
 776→	}
 777→
 778→	fmt.Fprintf(w, "✓ Project configured (%s)\n", configDisplayProject)
 779→
 780→	// Let the strategy handle its own setup requirements (creates entire/checkpoints/v1 branch, etc.)
 781→	strat, err := strategy.Get(settings.Strategy)
 782→	if err != nil {
 783→		return fmt.Errorf("failed to get strategy: %w", err)
 784→	}
 785→	if err := strat.EnsureSetup(); err != nil {
 786→		return fmt.Errorf("failed to setup strategy: %w", err)
 787→	}
 788→
 789→	fmt.Fprintln(w, "\nReady.")
 790→
 791→	return nil
 792→}
