 802→// determineSettingsTarget decides whether to write to settings.local.json based on:
 803→// - Whether settings.json already exists
 804→// - The --local and --project flags
 805→// Returns (useLocal, showNotification).
 806→func determineSettingsTarget(entireDir string, useLocal, useProject bool) (bool, bool) {
 807→	// Explicit --local flag always uses local settings
 808→	if useLocal {
 809→		return true, false
 810→	}
 811→
 812→	// Explicit --project flag always uses project settings
 813→	if useProject {
 814→		return false, false
 815→	}
 816→
 817→	// No flags specified - check if settings file exists
 818→	settingsPath := filepath.Join(entireDir, paths.SettingsFileName)
 819→	if _, err := os.Stat(settingsPath); err == nil {
 820→		// Settings file exists - auto-redirect to local with notification
 821→		return true, true
 822→	}
 823→
 824→	// Settings file doesn't exist - create it
 825→	return false, false
 826→}
