 828→// setupEntireDirectory creates the .entire directory and gitignore.
 829→// Returns true if the directory was created, false if it already existed.
 830→func setupEntireDirectory() (bool, error) { //nolint:unparam // already present in codebase
 831→	// Get absolute path for the .entire directory
 832→	entireDirAbs, err := paths.AbsPath(paths.EntireDir)
 833→	if err != nil {
 834→		entireDirAbs = paths.EntireDir // Fallback to relative
 835→	}
 836→
 837→	// Check if directory already exists
 838→	created := false
 839→	if _, err := os.Stat(entireDirAbs); os.IsNotExist(err) {
 840→		created = true
 841→	}
 842→
 843→	// Create .entire directory
 844→	//nolint:gosec // G301: Project directory needs standard permissions for git
 845→	if err := os.MkdirAll(entireDirAbs, 0o755); err != nil {
 846→		return false, fmt.Errorf("failed to create .entire directory: %w", err)
 847→	}
 848→
 849→	// Create/update .gitignore with all required entries
 850→	if err := strategy.EnsureEntireGitignore(); err != nil {
 851→		return false, fmt.Errorf("failed to setup .gitignore: %w", err)
 852→	}
 853→
 854→	return created, nil
 855→}
