 897→
 898→// shellCompletionComment is the comment preceding the completion line
 899→const shellCompletionComment = "# Entire CLI shell completion"
 900→
 901→// errUnsupportedShell is returned when the user's shell is not supported for completion.
 902→var errUnsupportedShell = errors.New("unsupported shell")
 903→
 904→// shellCompletionTarget returns the rc file path and completion lines for the
 905→// user's current shell.
 906→func shellCompletionTarget() (shellName, rcFile, completionLine string, err error) {
 907→	home, err := os.UserHomeDir()
 908→	if err != nil {
 909→		return "", "", "", fmt.Errorf("cannot determine home directory: %w", err)
 910→	}
 911→
 912→	shell := os.Getenv("SHELL")
 913→	switch {
 914→	case strings.Contains(shell, "zsh"):
 915→		return "Zsh",
 916→			filepath.Join(home, ".zshrc"),
 917→			"autoload -Uz compinit && compinit && source <(entire completion zsh)",
 918→			nil
 919→	case strings.Contains(shell, "bash"):
 920→		bashRC := filepath.Join(home, ".bashrc")
 921→		if _, err := os.Stat(filepath.Join(home, ".bash_profile")); err == nil {
 922→			bashRC = filepath.Join(home, ".bash_profile")
 923→		}
 924→		return "Bash",
 925→			bashRC,
 926→			"source <(entire completion bash)",
 927→			nil
 928→	case strings.Contains(shell, "fish"):
 929→		return "Fish",
 930→			filepath.Join(home, ".config", "fish", "config.fish"),
 931→			"entire completion fish | source",
 932→			nil
 933→	default:
 934→		return "", "", "", errUnsupportedShell
 935→	}
 936→}
 937→
 938→// promptShellCompletion offers to add shell completion to the user's rc file.
 939→// Only prompts if completion is not already configured.
 940→func promptShellCompletion(w io.Writer) error {
 941→	shellName, rcFile, completionLine, err := shellCompletionTarget()
 942→	if err != nil {
 943→		if errors.Is(err, errUnsupportedShell) {
 944→			fmt.Fprintf(w, "Note: Shell completion not available for your shell. Supported: zsh, bash, fish.\n")
 945→			return nil
 946→		}
 947→		return fmt.Errorf("shell completion: %w", err)
 948→	}
 949→
 950→	if isCompletionConfigured(rcFile) {
 951→		fmt.Fprintf(w, "✓ Shell completion already configured in %s\n", rcFile)
 952→		return nil
 953→	}
 954→
 955→	var selected string
 956→	form := NewAccessibleForm(
 957→		huh.NewGroup(
 958→			huh.NewSelect[string]().
 959→				Title(fmt.Sprintf("Enable shell completion? (detected: %s)", shellName)).
 960→				Options(
 961→					huh.NewOption("Yes", "yes"),
 962→					huh.NewOption("No", "no"),
 963→				).
 964→				Value(&selected),
 965→		),
 966→	)
 967→
 968→	if err := form.Run(); err != nil {
 969→		//nolint:nilerr // User cancelled - not a fatal error, just skip
 970→		return nil
 971→	}
 972→
 973→	if selected != "yes" {
 974→		return nil
 975→	}
 976→
 977→	if err := appendShellCompletion(rcFile, completionLine); err != nil {
 978→		return fmt.Errorf("failed to update %s: %w", rcFile, err)
 979→	}
 980→
 981→	fmt.Fprintf(w, "✓ Shell completion added to %s\n", rcFile)
 982→	fmt.Fprintln(w, "  Restart your shell to activate")
 983→
 984→	return nil
 985→}
 986→
 987→// isCompletionConfigured checks if shell completion is already in the rc file.
 988→func isCompletionConfigured(rcFile string) bool {
 989→	//nolint:gosec // G304: rcFile is constructed from home dir + known filename, not user input
 990→	content, err := os.ReadFile(rcFile)
 991→	if err != nil {
 992→		return false // File doesn't exist or can't read, treat as not configured
 993→	}
 994→	return strings.Contains(string(content), "entire completion")
 995→}
 996→
 997→// appendShellCompletion adds the completion line to the rc file.
 998→func appendShellCompletion(rcFile, completionLine string) error {
 999→	if err := os.MkdirAll(filepath.Dir(rcFile), 0o700); err != nil {
1000→		return fmt.Errorf("creating directory: %w", err)
1001→	}
1002→	//nolint:gosec // G302: Shell rc files need 0644 for user readability
1003→	f, err := os.OpenFile(rcFile, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
1004→	if err != nil {
1005→		return fmt.Errorf("opening file: %w", err)
1006→	}
1007→	defer f.Close()
1008→
1009→	_, err = f.WriteString("\n" + shellCompletionComment + "\n" + completionLine + "\n")
1010→	if err != nil {
1011→		return fmt.Errorf("writing completion: %w", err)
1012→	}
1013→	return nil
1014→}
