1016→// promptTelemetryConsent asks the user if they want to enable telemetry.
1017→// It modifies settings.Telemetry based on the user's choice or flags.
1018→// The caller is responsible for saving settings.
1019→func promptTelemetryConsent(settings *EntireSettings, telemetryFlag bool) error {
1020→	// Handle --telemetry=false flag first (always overrides existing setting)
1021→	if !telemetryFlag {
1022→		f := false
1023→		settings.Telemetry = &f
1024→		return nil
1025→	}
1026→
1027→	// Skip if already asked
1028→	if settings.Telemetry != nil {
1029→		return nil
1030→	}
1031→
1032→	// Skip if env var disables telemetry (record as disabled)
1033→	if os.Getenv("ENTIRE_TELEMETRY_OPTOUT") != "" {
1034→		f := false
1035→		settings.Telemetry = &f
1036→		return nil
1037→	}
1038→
1039→	consent := true // Default to Yes
1040→	form := NewAccessibleForm(
