1043→				Title("Help improve Entire CLI?").
1044→				Description("Share anonymous usage data. No code or personal info collected.").
1045→				Affirmative("Yes").
1046→				Negative("No").
1047→				Value(&consent),
1048→		),
1049→	)
1050→
1051→	if err := form.Run(); err != nil {
1052→		return fmt.Errorf("telemetry prompt: %w", err)
1053→	}
1054→
1055→	settings.Telemetry = &consent
1056→	return nil
1057→}
