1059→// runUninstall completely removes Entire from the repository.
1060→func runUninstall(w, errW io.Writer, force bool) error {
1061→	// Check if we're in a git repository
1062→	if _, err := paths.RepoRoot(); err != nil {
1063→		fmt.Fprintln(errW, "Not a git repository. Nothing to uninstall.")
1064→		return NewSilentError(errors.New("not a git repository"))
1065→	}
1066→
1067→	// Gather counts for display
1068→	sessionStateCount := countSessionStates()
1069→	shadowBranchCount := countShadowBranches()
1070→	gitHooksInstalled := strategy.IsGitHookInstalled()
1071→	claudeHooksInstalled := checkClaudeCodeHooksInstalled()
1072→	geminiHooksInstalled := checkGeminiCLIHooksInstalled()
1073→	entireDirExists := checkEntireDirExists()
1074→
1075→	// Check if there's anything to uninstall
1076→	if !entireDirExists && !gitHooksInstalled && sessionStateCount == 0 &&
1077→		shadowBranchCount == 0 && !claudeHooksInstalled && !geminiHooksInstalled {
1078→		fmt.Fprintln(w, "Entire is not installed in this repository.")
1079→		return nil
1080→	}
1081→
1082→	// Show confirmation prompt unless --force
1083→	if !force {
1084→		fmt.Fprintln(w, "\nThis will completely remove Entire from this repository:")
1085→		if entireDirExists {
1086→			fmt.Fprintln(w, "  - .entire/ directory")
1087→		}
1088→		if gitHooksInstalled {
1089→			fmt.Fprintln(w, "  - Git hooks (prepare-commit-msg, commit-msg, post-commit, pre-push)")
1090→		}
1091→		if sessionStateCount > 0 {
1092→			fmt.Fprintf(w, "  - Session state files (%d)\n", sessionStateCount)
1093→		}
1094→		if shadowBranchCount > 0 {
1095→			fmt.Fprintf(w, "  - Shadow branches (%d)\n", shadowBranchCount)
1096→		}
1097→		switch {
1098→		case claudeHooksInstalled && geminiHooksInstalled:
1099→			fmt.Fprintln(w, "  - Agent hooks (Claude Code, Gemini CLI)")
1100→		case claudeHooksInstalled:
1101→			fmt.Fprintln(w, "  - Agent hooks (Claude Code)")
1102→		case geminiHooksInstalled:
1103→			fmt.Fprintln(w, "  - Agent hooks (Gemini CLI)")
1104→		}
1105→		fmt.Fprintln(w)
1106→
1107→		var confirmed bool
1108→		form := NewAccessibleForm(
1109→			huh.NewGroup(
1110→				huh.NewConfirm().
1111→					Title("Are you sure you want to uninstall Entire?").
1112→					Affirmative("Yes, uninstall").
1113→					Negative("Cancel").
1114→					Value(&confirmed),
1115→			),
1116→		)
1117→
1118→		if err := form.Run(); err != nil {
1119→			return fmt.Errorf("confirmation cancelled: %w", err)
1120→		}
1121→
1122→		if !confirmed {
1123→			fmt.Fprintln(w, "Uninstall cancelled.")
1124→			return nil
1125→		}
1126→	}
1127→
1128→	fmt.Fprintln(w, "\nUninstalling Entire CLI...")
1129→
1130→	// 1. Remove agent hooks (lowest risk)
1131→	if err := removeAgentHooks(w); err != nil {
1132→		fmt.Fprintf(errW, "Warning: failed to remove agent hooks: %v\n", err)
1133→	}
1134→
1135→	// 2. Remove git hooks
1136→	removed, err := strategy.RemoveGitHook()
1137→	if err != nil {
1138→		fmt.Fprintf(errW, "Warning: failed to remove git hooks: %v\n", err)
1139→	} else if removed > 0 {
1140→		fmt.Fprintf(w, "  Removed git hooks (%d)\n", removed)
1141→	}
1142→
1143→	// 3. Remove session state files
1144→	statesRemoved, err := removeAllSessionStates()
1145→	if err != nil {
1146→		fmt.Fprintf(errW, "Warning: failed to remove session states: %v\n", err)
1147→	} else if statesRemoved > 0 {
1148→		fmt.Fprintf(w, "  Removed session states (%d)\n", statesRemoved)
1149→	}
1150→
1151→	// 4. Remove .entire/ directory
1152→	if err := removeEntireDirectory(); err != nil {
1153→		fmt.Fprintf(errW, "Warning: failed to remove .entire directory: %v\n", err)
1154→	} else if entireDirExists {
1155→		fmt.Fprintln(w, "  Removed .entire directory")
1156→	}
1157→
1158→	// 5. Remove shadow branches
1159→	branchesRemoved, err := removeAllShadowBranches()
1160→	if err != nil {
1161→		fmt.Fprintf(errW, "Warning: failed to remove shadow branches: %v\n", err)
1162→	} else if branchesRemoved > 0 {
1163→		fmt.Fprintf(w, "  Removed %d shadow branches\n", branchesRemoved)
1164→	}
1165→
1166→	fmt.Fprintln(w, "\nEntire CLI uninstalled successfully.")
1167→	return nil
1168→}
