1228→// removeAgentHooks removes hooks from all agents that support hooks.
1229→func removeAgentHooks(w io.Writer) error {
1230→	var errs []error
1231→
1232→	// Remove Claude Code hooks
1233→	claudeAgent, err := agent.Get(agent.AgentNameClaudeCode)
1234→	if err == nil {
1235→		if hookAgent, ok := claudeAgent.(agent.HookSupport); ok {
1236→			wasInstalled := hookAgent.AreHooksInstalled()
1237→			if err := hookAgent.UninstallHooks(); err != nil {
1238→				errs = append(errs, err)
1239→			} else if wasInstalled {
1240→				fmt.Fprintln(w, "  Removed Claude Code hooks")
1241→			}
1242→		}
1243→	}
1244→
1245→	// Remove Gemini CLI hooks
1246→	geminiAgent, err := agent.Get(agent.AgentNameGemini)
1247→	if err == nil {
1248→		if hookAgent, ok := geminiAgent.(agent.HookSupport); ok {
1249→			wasInstalled := hookAgent.AreHooksInstalled()
1250→			if err := hookAgent.UninstallHooks(); err != nil {
1251→				errs = append(errs, err)
1252→			} else if wasInstalled {
1253→				fmt.Fprintln(w, "  Removed Gemini CLI hooks")
1254→			}
1255→		}
1256→	}
1257→
1258→	return errors.Join(errs...)
1259→}
1260→
1261→// removeAllSessionStates removes all session state files and the directory.
1262→func removeAllSessionStates() (int, error) {
1263→	store, err := session.NewStateStore()
1264→	if err != nil {
1265→		return 0, fmt.Errorf("failed to create state store: %w", err)
1266→	}
1267→
1268→	// Count states before removing
1269→	states, err := store.List(context.Background())
1270→	if err != nil {
1271→		return 0, fmt.Errorf("failed to list session states: %w", err)
1272→	}
1273→	count := len(states)
1274→
1275→	// Remove the entire directory
1276→	if err := store.RemoveAll(); err != nil {
1277→		return 0, fmt.Errorf("failed to remove session states: %w", err)
1278→	}
1279→
1280→	return count, nil
1281→}
1282→
1283→// removeEntireDirectory removes the .entire directory.
1284→func removeEntireDirectory() error {
1285→	entireDirAbs, err := paths.AbsPath(paths.EntireDir)
1286→	if err != nil {
