1291→	}
1292→	return nil
1293→}
1294→
1295→// removeAllShadowBranches removes all shadow branches.
1296→func removeAllShadowBranches() (int, error) {
1297→	branches, err := strategy.ListShadowBranches()
1298→	if err != nil {
